// Solution
from typing import List

class Solution:
    def getFibonacci(self, n: int) -> List[int]:
        if n == 0:
            return []
        elif n == 1:
            return [0]
        elif n > 1:
            result = [0, 1]
            for i in range(2, n):
                result.append(result[i - 1] + result[i - 2])
            return result

def main():
    n = int(input())
    solution = Solution()
    result = solution.getFibonacci(n)
    print(' '.join(str(i) for i in result))

